"""
MKT Christ Commentary — Isaiah chapter 60
Run: python3 scripts/zc-christ-isaiah-60.py

Isaiah 60 is the vision of Zion's glory: the nations stream to the divine light,
the wealth of the nations flows in, the gates stand perpetually open. John quotes
vv.19-20 almost verbatim in Revelation 21-22. The Magi narrative (Matt 2) draws
from vv.3,6.

Key Christological texts:
- 60:1-3: "Arise, shine" → John 1:9; John 8:12; Eph 5:14; Rev 21:23
- 60:6: gold and frankincense → Matt 2:11 (Magi gifts)
- 60:11: gates never shut → Rev 21:25 (direct fulfillment)
- 60:18: walls = Salvation (Yeshua's name), gates = Praise → John 10:9
- 60:19-20: no sun/moon needed → Rev 21:23; 22:5 (near-verbatim citation)
- 60:22: smallest becomes mighty nation → Mark 4:31-32 (mustard seed)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "60": {
    "1": '<p>"Arise, shine, for your light has come, and the glory of YHWH has risen upon you." The call to arise and shine is simultaneously an announcement and a command — the light has come, therefore the arising is possible. John 8:12: "I am the light of the world." John 1:9: "the true light, which gives light to everyone, was coming into the world." Rev 21:23: "the city has no need of sun or moon to shine on it, for the glory of God gives it light, and its lamp is the Lamb." Eph 5:14: "Awake, O sleeper, and arise from the dead, and Christ will shine on you" — an early Christian hymn echoing Isaiah 60:1, applying it to the believer\'s encounter with the risen Christ. The glory of YHWH that "rises upon" Zion is the same glory that "rose upon" the shepherds\' fields (Luke 2:9: "the glory of the Lord shone around them").</p>',
    "2": '<p>"For behold, darkness shall cover the earth, and thick darkness the peoples; but YHWH will arise upon you, and his glory will be seen upon you." The contrast between cosmic darkness and the divine light. John 1:5: "the light shines in the darkness, and the darkness has not overcome it." John 3:19: "the light has come into the world, and people loved the darkness rather than the light because their works were evil." Matt 4:16 (quoting Isa 9:2): "the people dwelling in darkness have seen a great light, and for those dwelling in the region and shadow of death, on them a light has dawned." The thick darkness (<em>ʿărāp̄el</em>) that covers the peoples is the condition that the incarnation addresses — YHWH arising on Zion in Christ, his glory visible to those who looked on him (John 1:14: "we have seen his glory").</p>',
    "3": '<p>"And nations shall come to your light, and kings to the brightness of your rising." Rev 21:24: "by its light will the nations walk, and the kings of the earth will bring their glory into it." Matt 2:1-12: Magi from the East coming toward a light (a star) — the partial first-fulfillment at the nativity. Rev 21:26: "they will bring into it the glory and the honor of the nations." The nations coming to the light is the entire Gentile mission in nuce: Acts 13:47 (Paul quoting Isa 49:6: "I have made you a light for the Gentiles, that you may bring salvation to the ends of the earth"); Acts 28:28 (the gospel going to the Gentiles who "will listen"). The brightness of Christ\'s rising is the resurrection light that draws all nations.</p>',
    "4": '<p>"Lift up your eyes all around, and see; they all gather together, they come to you; your sons shall come from afar, and your daughters shall be carried on the hip." The gathering of scattered children. John 11:51-52: Caiaphas\'s unwitting prophecy that "Jesus would die for the nation, and not for the nation only, but also to gather into one the children of God who are scattered abroad." John 10:16: "I have other sheep that are not of this fold. I must bring them also, and they will listen to my voice. So there will be one flock, one shepherd." Rev 21:2: the new Jerusalem coming down — the gathering-point of all the scattered children. The daughters "carried on the hip" (ʿal-ṣad tiṭṭāʾanāh, borne on the side) is the tender image of safe transport — the Good Shepherd who carries the lost sheep on his shoulders (Luke 15:5).</p>',
    "5": '<p>"Then you shall see and be radiant; your heart shall thrill and exult, because the abundance of the sea shall be turned to you, the wealth of the nations shall come to you." The transformation of the seeing community — not just sight but radiance. 2 Cor 3:18: "we all, with unveiled face, beholding the glory of the Lord, are being transformed into the same image from one degree of glory to another." The "abundance of the sea" (hmōn yām) is the commerce of the Gentile world redirected to serve God\'s city. Rev 21:26: "they will bring into it the glory and the honor of the nations." The economic imagery throughout Isaiah 60 anticipates the universal scope of the new creation — all human culture redeemed and brought into the City of God.</p>',
    "6": '<p>"A multitude of camels shall cover you, the young camels of Midian and Ephah; all those from Sheba shall come. They shall bring gold and frankincense, and shall bring good news, the praises of YHWH." The gold and frankincense that the Sheba caravans bring are the specific gifts the Magi offer to the infant Christ: Matt 2:11: "they offered him gifts, gold and frankincense and myrrh." Isaiah 60:6 is the OT foundation for the Magi narrative. The Sheba connection also activates Matt 12:42: "the queen of the South will rise up at the judgment with this generation and condemn it, for she came from the ends of the earth to hear the wisdom of Solomon, and behold, something greater than Solomon is here." The Sheba journey that was about Solomon\'s wisdom is fulfilled in the Magi\'s journey to the one who is Wisdom incarnate (1 Cor 1:30: "Christ Jesus, who became to us wisdom from God").</p>',
    "7": '<p>"All the flocks of Kedar shall be gathered to you; the rams of Nebaioth shall minister to you; they shall come up with acceptance on my altar, and I will beautify my beautiful house." Gentile sacrifice accepted on the altar. Rom 15:16: Paul describes his apostolic ministry as "the priestly service of the gospel of God, so that the offering of the Gentiles may be acceptable, sanctified by the Holy Spirit" — Paul understands his mission as fulfilling Isaiah 60:7. 1 Pet 2:5: "you yourselves like living stones are being built up as a spiritual house, to be a holy priesthood, to offer spiritual sacrifices acceptable to God through Jesus Christ." The "beautiful house" made beautiful by the Gentile offerings anticipates the new Jerusalem that needs no temple "for its temple is the Lord God the Almighty and the Lamb" (Rev 21:22).</p>',
    "8": '<p>"Who are these that fly like a cloud, and like doves to their windows?" The rapid, simultaneous ingathering of peoples from all directions — the speed of their coming likened to clouds and homing doves. Acts 2:5-11: "devout Jews from every nation under heaven" converging on Jerusalem at Pentecost — the first mass gathering of the dispersed nations to Zion. Rev 7:9: "a great multitude that no one could number, from every nation, from all tribes and peoples and languages, standing before the throne and before the Lamb." The question "who are these?" is the Seer\'s question before the innumerable multitude, answered in Rev 7:14: "these are the ones coming out of the great tribulation." The cloud of witnesses rushing home.</p>',
    "9": '<p>"For the coastlands shall hope for me, the ships of Tarshish first, to bring your children from afar, their silver and gold with them, for the name of YHWH your God, and for the Holy One of Israel, because he has made you beautiful." The coastlands that wait (42:4: "the coastlands wait for his Torah") now actively hope and send ships. Acts 13:47: Paul and Barnabas turn to the Gentiles at Antioch of Pisidia quoting Isa 49:6 — "I have made you a light for the Gentiles" — and the Gentiles "began rejoicing and glorifying the word of the Lord." The ships of Tarshish recall Jonah\'s attempted escape — the same vessels that carried the prophet away from God\'s mission are now the vessels of the ingathering. Christ redirects even resistance into mission.</p>',
    "10": '<p>"Foreigners shall build up your walls, and their kings shall minister to you; for in my wrath I struck you, but in my favor I have had mercy on you." The enemies who demolished now rebuild. Eph 2:12-14: Gentiles "who once were far off have been brought near by the blood of Christ. For he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility." The foreigners building Zion\'s walls is the reversal of Babylon\'s conquest — the very nations that destroyed the temple become the nations that contribute to the new Jerusalem (Rev 21:24-26). The divine wrath/favor dialectic: "in my wrath I struck you, but in my favor I have had mercy" = Rom 11:22: "the kindness and the severity of God." The mercy in Christ\'s favor is the permanent condition.</p>',
    "11": '<p>"Your gates shall be open continually; day and night they shall not be shut, that people may bring to you the wealth of the nations, with their kings led in procession." Rev 21:25: "its gates will never be shut by day — and there will be no night there." John\'s vision copies Isaiah 60:11 almost verbatim. The perpetually open gates are the eschatological hospitality of the city of God — no night (when gates would be shut for safety), no exclusion of those who come bearing the nations\' glory. John 10:9: "I am the door; if anyone enters by me, he will be saved and will go in and out and find pasture." Christ is the open gate — the permanent access to the Father (John 14:6: "no one comes to the Father except through me") that never shuts.</p>',
    "12": '<p>"For the nation and kingdom that will not serve you shall perish; those nations shall be utterly laid waste." The judgment on those who refuse the city. Matt 25:31-46: the judgment of the nations — those who served the least of Christ\'s brothers ("I was hungry and you gave me food") enter the kingdom; those who refused are sent to eternal punishment. Rev 19:15-21: the destruction of the nations that gathered to make war against the Lamb. The universal welcome of the open gates (v.11) has its dark counterpart in the universal accountability of v.12 — the same city that receives the repentant excludes the impenitent (Rev 21:27: "nothing unclean will ever enter it, nor anyone who does what is detestable or false").</p>',
    "13": '<p>"The glory of Lebanon shall come to you, the cypress, the plane, and the pine, to beautify the place of my sanctuary, and I will make the place of my feet glorious." The temple wood of Lebanon (1 Kings 5:6-10 — the cedar and cypress for Solomon\'s temple) now coming willingly. Rev 21:10-11: the new Jerusalem "having the glory of God, its radiance like a most rare jewel." John 14:2-3: "In my Father\'s house are many rooms... I go to prepare a place for you." The "place of my feet" (<em>mĕqôm raglāy</em>) is the footstool, the earthly temple-dwelling — but in Christ\'s incarnation, the place of God\'s feet is Galilee, Bethlehem, Gethsemane. Col 1:19: "in him all the fullness of God was pleased to dwell" — the sanctuary-place where YHWH\'s feet rest is the flesh of Christ.</p>',
    "14": '<p>"The sons of those who afflicted you shall come bending low to you, and all who despised you shall bow down at your feet; they shall call you the City of YHWH, the Zion of the Holy One of Israel." Phil 2:10-11: "every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord, to the glory of God the Father." Rev 3:9: the letter to Philadelphia — "I will make them come and bow down before your feet and they will learn that I have loved you." The reversal of social power — former oppressors in prostration before the formerly despised — is the eschatological vindication that follows the pattern of Christ: "despised and rejected by men" (53:3) becoming "the Lord of glory" (1 Cor 2:8) before whom all will bow.</p>',
    "15": '<p>"Whereas you have been forsaken and hated, with no one passing through, I will make you majestic forever, a joy from age to age." The transformation from abandoned to eternally majestic. Ps 22:1,24: the one who cried "my God, why have you forsaken me?" is also the one of whom it is said "he has not despised or scorned the suffering of the afflicted one." The abandoned Zion parallels the abandoned Christ — "forsaken" (<em>ʿăzûḇâ</em>) is Christ\'s Gethsemane experience (Matt 26:56: "all the disciples left him and fled") and the cry of dereliction (Matt 27:46). The "majestic forever" is the exaltation that follows the abandonment: Phil 2:9: "God has highly exalted him and bestowed on him the name that is above every name." Rev 21:11: the new Jerusalem radiates "the glory of God."</p>',
    "16": '<p>"You shall drink the milk of nations; you shall nurse at the breast of kings; and you shall know that I, YHWH, am your Savior and your Redeemer, the Mighty One of Jacob." The nursing metaphor of divine provision — Zion nourished by what was once threatening. Rev 21:26: the nations bringing their glory into the city. The title "Savior and Redeemer" (<em>mōšîaʿ</em> and <em>gōʾēl</em>) is the double divine identity — Savior = the name Jesus (Yēšûaʿ); Redeemer = the kinsman who pays the price (Gal 3:13; 1 Pet 1:18-19). John 4:42: "we know that this is indeed the Savior of the world." The "knowing that I, YHWH, am your Savior" is the knowledge that John\'s Gospel aims to produce through its signs: "these are written so that you may believe that Jesus is the Christ, the Son of God" (John 20:31).</p>',
    "17": '<p>"Instead of bronze I will bring gold, and instead of iron I will bring silver; instead of wood, bronze, instead of stones, iron. I will make your overseers peace and your taskmasters righteousness." The eschatological upgrade from inferior to precious. Heb 12:18-24: the contrast between Mount Sinai ("blazing fire and darkness and gloom and a tempest") and Mount Zion ("the city of the living God, the heavenly Jerusalem"). The governance of the new city — "overseers of peace" (<em>šōṭĕrê šālôm</em>) and "taskmasters of righteousness" — is the reversal of Egypt\'s taskmasters (Exod 5:10-14) and Babylon\'s oppressors. Isa 9:6: "Prince of Peace" — Christ is the one whose name is shalom, the true overseer. Rev 22:5: his servants will "reign forever and ever" under the one who is righteousness itself (1 Cor 1:30).</p>',
    "18": '<p>"Violence shall no more be heard in your land, devastation or destruction within your borders; you shall call your walls Salvation, and your gates Praise." The walls named <em>Yĕšûʿâ</em> (Salvation — the same Hebrew root as "Jesus") and the gates named <em>Tĕhillâ</em> (Praise). John 10:9: "I am the door; if anyone enters by me, he will be saved" — Christ himself is the gate named Salvation. Rev 19:1: "Hallelujah! Salvation and glory and power belong to our God" — the praise that names the gates resounds in the heavenly worship. The absence of violence, devastation, and destruction anticipates Rev 21:4: "death shall be no more, neither shall there be mourning, nor crying, nor pain anymore." The walls and gates are Christ himself — he is both the protection (Salvation) and the worship-response (Praise) of the new city.</p>',
    "19": '<p>"The sun shall be no more your light by day, nor for brightness shall the moon give you light; but YHWH will be your everlasting light, and your God will be your glory." Rev 21:23: "the city has no need of sun or moon to shine on it, for the glory of God gives it light, and its lamp is the Lamb." John\'s apocalyptic vision is a near-verbatim quotation of Isaiah 60:19-20. John 1:4-5: "in him was life, and the life was the light of men. The light shines in the darkness." Rev 22:5: "they will need no light of lamp or sun, for the Lord God will be their light, and they will reign forever and ever." The lamp of the new Jerusalem is the Lamb — Christ is the eternal light that makes the created light of sun and moon unnecessary. 1 John 1:5: "God is light, and in him is no darkness at all."</p>',
    "20": '<p>"Your sun shall no more go down, nor your moon withdraw itself; for YHWH will be your everlasting light, and your days of mourning shall be ended." The setting sun that marks the end of days is abolished — the eternal day of YHWH\'s presence. Rev 21:4: "death shall be no more, neither shall there be mourning, nor crying, nor pain anymore, for the former things have passed away." John 11:25-26: "I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live, and everyone who lives and believes in me shall never die." The "days of mourning ended" is the resurrection promise — the grief of death and exile permanently reversed. 1 Thess 4:17-18: "we will always be with the Lord. Therefore encourage one another with these words." The everlasting light of 60:20 is the comfort Paul draws from the resurrection.</p>',
    "21": '<p>"Your people shall all be righteous; they shall possess the land forever, the branch of my planting, the work of my hands, that I might be glorified." The eschatological community defined by righteousness — not self-achieved but divinely planted. John 15:1-5: "I am the true vine, and my Father is the vinedresser... every branch in me that does not bear fruit he takes away, and every branch that does bear fruit he prunes, that it may bear more fruit." The people as "the branch of my planting, the work of my hands" is the planting metaphor of John 15. Rom 5:19: "by the one man\'s obedience the many will be made righteous." 2 Cor 5:21: "so that in him we might become the righteousness of God." The "all righteous" community is the church clothed in Christ\'s righteousness — "for my glorification" is the telos of the whole redemptive plan (Eph 1:12,14).</p>',
    "22": '<p>"The least one shall become a clan, and the smallest one a mighty nation; I am YHWH; in its time I will hasten it." The divine acceleration of growth from smallest to greatest. Mark 4:30-32: "with what can we compare the kingdom of God, or what parable shall we use for it? It is like a grain of mustard seed, which, when sown on the ground, is the smallest of all the seeds on earth, yet when it is sown it grows up and becomes larger than all the garden plants." Matt 13:31-32 applies the same mustard-seed parable — the smallest beginning (a handful of disciples in an obscure corner of the empire) becomes a community that fills the earth. "I am YHWH; in its time I will hasten it" — the sovereign divine timing. Acts 1:7: "it is not for you to know times or seasons that the Father has fixed by his own authority." The \'hastening\' of the eschaton is the prerogative of the Father who keeps the timing of the new creation\'s completion.</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all 22 Isaiah 60 mkt-christ verses present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 60 verse count changes, update expected total
    # VERIFY: Console shows OK with 22 verses; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    missing = [v for v in il.get('60', {}) if v not in out.get('60', {})]
    if missing:
        print(f'  MISSING ch 60: {missing}')
    else:
        print(f'  OK: all Isaiah 60 mkt-christ verses present ({len(il.get("60", {}))} verses)')

if __name__ == '__main__':
    main()
